content:
    }

    self.docker
        .remove_container(
            spoke_name,
            Some(RemoveContainerOptions {
                force,
                ..Default::default()
            }),
        )
        .await
        .map_err(|e| {
            CorviaError::Docker(format!("Failed to remove spoke '{spoke_name}': {e}"))
        })?;

    info!(spoke_name, "Spoke destroyed");
    Ok(())
}

/// Destroy all spoke containers. Returns (success_count, failed_names).
pub async fn destroy_all(&self, force: bool) -> Result<(u32, Vec<String>)> {
    let spokes = self.list(true).await?;
    let mut success = 0u32;
    let mut failures = Vec::new();
    for spoke in &spokes {
        match self.destroy(&spoke.name, force).await {
            Ok(()) => success += 1,
            Err(e) => {
                warn!(spoke = %spoke.name, error = %e, "Failed to destroy spoke");
                failures.push(spoke.name.clone());
            }
        }
    }
    Ok((success, failures))
}

/// Restart a spoke container, preserving its filesystem.
pub async fn restart(&self, spoke_name: &str) -> Result<()> {
    let span = info_span!("corvia.spoke.restart", spoke_name);
    self.restart_inner(spoke_name).instrument(span).await
}
